16	export interface Scenario {
17	  customer: Customer;
18	  steps: Step[];
19	}
20	
21	export interface QuoteResult {
22	  premium: number;
23	}
24	
25	export type StepResult = QuoteResult;
26	
27	export interface ScenarioResult {
28	  results: StepResult[];
29	}
30	
31	const basePremiums: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	};
37	
38	const PROCESSING_FEE = 5;
39	
40	export function runScenario(scenario: Scenario): ScenarioResult {
41	  const results = scenario.steps.map((step) => {
42	    const base = basePremiums[step.items[0].type];
43	    return { premium: base + PROCESSING_FEE };
44	  });
45	  return { results };
46	}
